import{_ as t,o as e,c as i,a0 as r}from"./chunks/framework.AQcSKqPn.js";const p=JSON.parse('{"title":"菜月昴 (Subaru Natsuki)","description":"","frontmatter":{"type":"entity","title":"菜月昴 (Subaru Natsuki)","created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","tags":["re-zero","character","protagonist"],"related":["re-zero-4th-season","rem","authority-of-gluttony","pleiades-watchtower","sage-shaula"],"sources":["anime/61316.md"]},"headers":[],"relativePath":"entities/菜月昴-subaru-natsuki.md","filePath":"entities/菜月昴-subaru-natsuki.md","lastUpdated":1783752665000}'),u={name:"entities/菜月昴-subaru-natsuki.md"};function s(o,a,l,n,h,d){return e(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="菜月昴-subaru-natsuki" tabindex="-1">菜月昴 (Subaru Natsuki) <a class="header-anchor" href="#菜月昴-subaru-natsuki" aria-label="Permalink to &quot;菜月昴 (Subaru Natsuki)&quot;">​</a></h1><p>菜月昴（Subaru Natsuki）是《Re:Zero kara Hajimeru Isekai Seikatsu》系列的主角。在第四季中，他面临着前所未有的挑战。</p><h2 id="第四季中的角色定位" tabindex="-1">第四季中的角色定位 <a class="header-anchor" href="#第四季中的角色定位" aria-label="Permalink to &quot;第四季中的角色定位&quot;">​</a></h2><p>在经历了水门都市普利斯特拉的惨胜后，昴的同伴们——雷姆、库珥修、尤里乌斯——被&quot;暴食&quot;权能（<a href="/llm-wiki/concepts/暴食权能-authority-of-gluttony">authority-of-gluttony</a>）吞噬了存在。昴因此承担起寻找解救方法的责任。他的下一个目标是寻找全知的&quot;贤者&quot;莎缇拉（<a href="/llm-wiki/entities/贤者莎缇拉-sage-shaula">sage-shaula</a>），并前往贤者之塔（<a href="/llm-wiki/entities/贤者之塔-pleiades-watchtower">pleiades-watchtower</a>）。</p><h2 id="核心动机" tabindex="-1">核心动机 <a class="header-anchor" href="#核心动机" aria-label="Permalink to &quot;核心动机&quot;">​</a></h2><p>昴在本季的核心动机是拯救被剥夺存在的同伴。与以往的战斗不同，这次他面对的不是可以靠&quot;死亡回归&quot;简单重来的物理威胁，而是对同伴存在本身的抹除。这迫使他必须寻找新的解决路径，而非依赖重复的试错。</p><h2 id="关键行动" tabindex="-1">关键行动 <a class="header-anchor" href="#关键行动" aria-label="Permalink to &quot;关键行动&quot;">​</a></h2><ul><li>在普利斯特拉战役中勉强取得胜利</li><li>得知&quot;贤者&quot;莎缇拉的存在</li><li>决定前往贤者之塔寻求解救同伴的方法</li></ul>',8)])])}const _=t(u,[["render",s]]);export{p as __pageData,_ as default};
